        \DB::table('posts')->insert(array (
            0 => 
            array (
                'id' => 1,
                'title' => 'Jack Miller – Ngôi sao rực sáng của làng BMX Anh Quốc',
                'slug' => 'jack-miller-ngoi-sao-ruc-sang-cua-lang-bmx-anh-quoc',
            'content' => '<h1 class="article-title" style="margin: 20px 0px 25px; font-size: 24px; font-family: &quot;Product Sans&quot;; line-height: 28px; color: rgb(37, 37, 37); letter-spacing: 0.01em; float: left; width: 870px;">Jack Miller – Ngôi sao rực sáng của làng BMX Anh Quốc</h1><div class="article-content" style="font-size: 14px; width: 870px; float: left; margin-top: 10px; color: rgb(37, 37, 37); font-family: &quot;Product Sans&quot;;"><div class="rte" style="color: rgb(94, 95, 95); margin-top: 5px; width: 870px; float: left; margin-bottom: 30px;"><p data-end="548" data-start="141" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;"><em><span style="font-weight: 700;">Jack Miller</span>&nbsp;là một trong những tài năng sáng giá nhất của làng BMX Anh Quốc. Sinh ra và lớn lên tại Inverness, nằm sâu trong vùng cao nguyên Scotland,&nbsp;<span style="font-weight: 700;">Jack</span>&nbsp;đã rèn luyện kỹ năng của mình từ khi còn rất nhỏ, theo bước chân của cha mình – một tay đua BMX kỳ cựu. Khởi đầu từ công viên địa phương ở Inverness,&nbsp;<span style="font-weight: 700;">Jack</span>&nbsp;dần phát triển niềm đam mê với BMX đường phố khi chuyển đến Newcastle, miền Đông Bắc nước Anh.</em></span></p><p data-end="929" data-start="550" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;"><em>Giờ đây,&nbsp;<span style="font-weight: 700;">Jack</span>&nbsp;là một trong những gương mặt đại diện cho thế hệ mới của BMX đường phố – phong cách kỹ thuật cao, yên xe nâng cao, khả năng điều khiển linh hoạt cả hai tay cùng với gu thời trang đậm chất thập niên 90. Nhân dịp phần video&nbsp;<em data-end="799" data-start="786">High Flyers</em>&nbsp;của anh với Dig Magazine sắp ra mắt, chúng tôi đã bắt máy gọi ngay cho&nbsp;<span style="font-weight: 700;">Jack</span>&nbsp;để tìm hiểu xem anh chàng đang có những dự định gì.</em></span></p><p data-end="929" data-start="550" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><em><img data-thumb="original" original-height="552" original-width="1380" src="https://bizweb.dktcdn.net/100/140/774/files/250224-vans-np-jackmiller-hero-desk.jpg?v=1741574319825" style="border: 0px none; max-width: 100%; height: auto; margin: 0px;"></em></p><h3 data-end="982" data-start="936" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Hãy giới thiệu một chút về bản thân bạn?</span></span></span></h3><p data-end="1231" data-start="984" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Mình là&nbsp;<span style="font-weight: 700;">Jack Miller</span>, 22 tuổi, đến từ Inverness, Scotland nhưng hiện tại đang sống ở Newcastle. Mẹ mình chuyển đến đây khi mình 17 tuổi, và mình quyết định theo bà vì Newcastle có một cộng đồng BMX năng động hơn nhiều so với việc ở lại Inverness.</span></p><h3 data-end="1286" data-start="1233" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Hành trình của bạn với BMX bắt đầu như thế nào?</span></span></span></h3><p data-end="1576" data-start="1288" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Mình bắt đầu BMX từ khi mới 3 tuổi, nhờ có bố – ông ấy cũng chơi BMX và đến giờ vẫn còn chạy xe. Hai bố con mình tập luyện cùng nhau đến khi mình khoảng 16 tuổi, cùng với nhóm bạn thân tại Inverness. Chúng mình luôn quay video, ghi lại những khoảnh khắc luyện tập và phát triển dần dần.</span></p><p data-end="1939" data-start="1578" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Sau khi chuyển đến Newcastle, mình bắt đầu được Waller BMX ở Sheffield chú ý và trở thành thành viên của đội – mình luôn biết ơn họ. Từ đó, mình được xuất hiện trên trang&nbsp;<em data-end="1762" data-start="1749">Ride UK BMX</em>, rồi lần lượt gia nhập&nbsp;<em data-end="1816" data-start="1786">Seventies, Stranger, Federal</em>&nbsp;và&nbsp;<em data-end="1828" data-start="1820">Cinema</em>. Sau đó, Alex – Team Manager của&nbsp;<span style="font-weight: 700;">Vans</span>&nbsp;– đã liên hệ với mình vài năm trước. Đó thực sự là một bước ngoặt lớn!</span></p><h3 data-end="1987" data-start="1941" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Cộng đồng BMX tại Newcastle như thế nào?</span></span></span></h3><p data-end="2243" data-start="1989" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Cảnh BMX ở Newcastle thực sự rất chất lượng. Hầu hết mọi người đều có công việc toàn thời gian, vì vậy thường chỉ có mình và Charlie – người quay phim chính của mình – ra ngoài quay và chụp ảnh. Cuối tuần, khi thời tiết đẹp, cả nhóm sẽ tụ tập đông hơn.</span></p><p data-end="2485" data-start="2245" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Chúng mình chủ yếu tập trung vào BMX đường phố, với một địa điểm quen thuộc là&nbsp;<em data-end="2333" data-start="2324">Sandman</em>. Đây là một bãi ledge ngay cạnh khách sạn Sandman, có thể coi như “phiên bản nhỏ” của&nbsp;<em data-end="2430" data-start="2420">Parallel</em>&nbsp;ở Barcelona. Nhóm mình thường xuyên tập luyện ở đây!</span></p><h3 data-end="2540" data-start="2487" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Một ngày điển hình của bạn diễn ra như thế nào?</span></span></span></h3><p data-end="2825" data-start="2542" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Mình thức dậy, bật nhạc ngay lập tức – âm nhạc là một phần không thể thiếu trong cuộc sống của mình. Sau đó nhìn ra ngoài cửa sổ kiểm tra thời tiết. Nếu trời khô ráo, mình sẽ gặp Charlie để quay phim và tập luyện. Sau đó, chúng mình trở về, xem lại cảnh quay, chỉnh sửa và ăn uống.</span></p><p data-end="2943" data-start="2827" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Nếu trời mưa, mình sẽ cố gắng vận động bằng cách đi leo núi – một thứ hoàn toàn khác với BMX nhưng vẫn rất thú vị!</span></p><p data-end="2943" data-start="2827" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><em><img data-thumb="original" original-height="552" original-width="1380" src="https://bizweb.dktcdn.net/100/140/774/files/250224-vans-np-jackmiller-img1-desk.jpg?v=1741574321557" style="border: 0px none; max-width: 100%; height: auto; margin: 0px;"></em></p><h3 data-end="3006" data-start="2945" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Bạn thích địa điểm nào nhất để đạp BMX ngoài Newcastle?</span></span></span></h3><p data-end="3222" data-start="3008" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Thật khó để chọn! Nhưng mình luôn yêu thích Inverness – nơi mình lớn lên và cũng là nơi có công viên BMX tuyệt nhất theo quan điểm của mình. Ngoài ra, Glasgow cũng rất tuyệt, Brighton có những công viên đỉnh cao.</span></p><p data-end="3422" data-start="3224" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Tháng 12 năm ngoái, mình đến Porto cùng đội&nbsp;<em data-end="3276" data-start="3268">Doomed</em>&nbsp;– thương hiệu thời trang mà mình đang đại diện. Thời tiết cũng khá giống Anh, không lý tưởng lắm, nhưng địa điểm tập luyện thì cực kỳ ấn tượng.</span></p><p data-end="3630" data-start="3424" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Nhưng nếu phải chọn một nơi, mình sẽ chọn Barcelona. Ở đó có một cộng đồng BMX vô cùng tuyệt vời, mọi người chỉ tập trung vào việc đạp xe và tận hưởng niềm vui. Mỗi lần đến đó, mình đều không muốn rời đi.</span></p><h3 data-end="3684" data-start="3632" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Bạn đánh giá thế nào về cộng đồng BMX tại Anh?</span></span></span></h3><p data-end="3889" data-start="3686" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Cộng đồng BMX ở Anh hiện tại đang bùng nổ. Có những sự kiện&nbsp;<em data-end="3761" data-start="3746">Backyard Jams</em>&nbsp;được tổ chức thường xuyên, nơi mà trình độ của các tay đua ngày càng đỉnh cao, ai cũng muốn thúc đẩy bản thân để tiến bộ hơn.</span></p><p data-end="4125" data-start="3891" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Glasgow đang dẫn đầu với nhóm&nbsp;<em data-end="3931" data-start="3921">BSD Boys</em>, trong khi Hastings là trung tâm của sự kiện&nbsp;<em data-end="3997" data-start="3977">Battle of Hastings</em>&nbsp;tại&nbsp;<em data-end="4015" data-start="4002">Source Park</em>. Ngoài ra, Bristol cũng đang phát triển mạnh. Nói chung, cộng đồng BMX ở Anh chưa bao giờ sôi động đến thế!</span></p><h3 data-end="4157" data-start="4127" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Bạn đang làm gì gần đây?</span></span></span></h3><p data-end="4395" data-start="4159" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Charlie và mình vừa hoàn thành phần video&nbsp;<em data-end="4219" data-start="4201">Vans High Flyers</em>&nbsp;với Dig Magazine. Chúng mình chỉ mất khoảng hai đến ba tháng để thực hiện – một khoảng thời gian khá nhanh, nhưng điều đó giúp cả hai luôn trong trạng thái tập trung cao độ.</span></p><p data-end="4531" data-start="4397" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Phần lớn cảnh quay được thực hiện ở Newcastle, nhưng chúng mình cũng có một tuần ở Barcelona để quay nốt một số phân đoạn cuối cùng.</span></p><h3 data-end="4599" data-start="4533" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Cảm giác khi trở thành thành viên của Vans BMX Team thế nào?</span></span></span></h3><p data-end="4805" data-start="4601" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Tuyệt vời. Đôi khi mình vẫn không tin điều này là thật. Từ nhỏ, mình đã thần tượng những tay đua&nbsp;<span style="font-weight: 700;">Vans</span>, và bố mình cũng mua&nbsp;<span style="font-weight: 700;">Vans</span>&nbsp;cho mình từ bé. Trở thành một phần của đội này là giấc mơ thành hiện thực.</span></p><p data-end="5019" data-start="4807" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Alex – Team Manager của&nbsp;<span style="font-weight: 700;">Vans</span>&nbsp;– là người mình đã từng xem video hồi nhỏ để lấy cảm hứng. Và bây giờ, mình có thể nhấc điện thoại lên, gọi cho anh ấy và cùng nhau tham gia các chuyến đi BMX. Điều đó thật điên rồ!</span></p><p data-end="5019" data-start="4807" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><em><img data-thumb="original" original-height="552" original-width="1380" src="https://bizweb.dktcdn.net/100/140/774/files/250224-vans-np-jackmiller-img2-desk.jpg?v=1741574322911" style="border: 0px none; max-width: 100%; height: auto; margin: 0px;"></em></p><h3 data-end="5077" data-start="5021" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Ai hoặc điều gì truyền cảm hứng cho bạn trong BMX?</span></span></span></h3><p data-end="5309" data-start="5079" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Bố mình là người truyền cảm hứng lớn nhất. Ông luôn thúc đẩy mình tập luyện và tiến bộ hơn. Ngoài ra, nhìn thấy các tay đua trẻ phát triển cũng khiến mình cảm thấy phấn khích – chúng nhắc nhở mình về chính bản thân mình lúc nhỏ.</span></p><p data-end="5491" data-start="5311" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Cộng đồng BMX ở Barcelona cũng là một nguồn cảm hứng to lớn. Mọi người ở đó đều tràn đầy năng lượng, luôn sẵn sàng tập luyện và tận hưởng niềm vui – điều quan trọng nhất của BMX.</span></p><h3 data-end="5551" data-start="5493" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Còn ngoài BMX thì sao? Điều gì khiến bạn phấn khích?</span></span></span></h3><p data-end="5692" data-start="5553" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Mình rất đam mê thời trang. Mình tin rằng thời trang là một phần quan trọng của BMX – khi mặc đẹp, bạn sẽ cảm thấy tự tin hơn khi đạp xe.</span></p><p data-end="5984" data-start="5694" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Mình cũng tham gia nhiều sự kiện DJ, vì nhiều bạn bè của mình làm DJ. Âm nhạc có ảnh hưởng lớn đến cách mình cảm nhận BMX, và mình cũng rất kỹ tính khi chọn nhạc cho các video BMX của mình. Mình thích dùng nhạc điện tử để tạo cảm giác vui vẻ, kích thích mọi người muốn ra ngoài và đạp xe.</span></p><p data-end="6102" data-start="5986" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Ngoài ra, mình còn thích vẽ trên quần áo – gần đây mình dành nhiều thời gian cho việc này và thực sự tận hưởng nó.</span></p><h3 data-end="6153" data-start="6104" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Đôi giày Vans yêu thích của bạn để đạp BMX?</span></span></span></h3><p data-end="6182" data-start="6155" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Chắc chắn là&nbsp;<span style="font-weight: 700;"><em data-end="6179" data-start="6168">Half Cabs</em></span>!</span></p><h3 data-end="6217" data-start="6184" style="line-height: 1.4; color: rgb(37, 37, 37); margin-top: 2em; margin-bottom: 10px; font-size: 24px; letter-spacing: 0.01em; text-align: justify;"><span style="font-size: 14px;"><span style="font-family: Arial, Helvetica, sans-serif;"><span style="font-weight: 700;">Lời nhắn cuối cùng của bạn?</span></span></span></h3><p data-end="6391" data-start="6219" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;"><span style="font-family: Arial, Helvetica, sans-serif;">Cảm ơn tất cả những ai đã ủng hộ mình – gia đình, bạn bè, và các nhà tài trợ. Hãy ra ngoài, đạp xe, quay phim và tận hưởng khoảng thời gian tuyệt vời với bạn bè của mình!</span></p><p data-end="6391" data-start="6219" style="margin-right: 0px; margin-bottom: 15px; margin-left: 0px; text-align: justify;">Nguồn: Vans.eu</p></div></div>',
                'thumbnail' => 'thumbnail/posts/1D4gofXuxNKd5YNM7H23s68Eftu066lKVFAcnVmW.png',
                'is_published' => 1,
                'published_at' => '2025-08-26 00:00:00',
